    )) {
      signals.push("Overdue invoice");
    }

    // Delayed shipment: no delivered date AND past SLA date
    if ((account.shipments || []).some(s =>
      !s.deliveredDate && new Date(s.slaDate) < nowDate
    )) {
      signals.push("Delayed shipment");
